  'type' => 'function',
  'function' => 
  array (
    'name' => 'image_analysis',
    'description' => 'Process an image file using PHP\'s GD extension: find dominant colors, compute color histogram, detect if mostly dark/light, extract average brightness, and report primary color palette. Takes any image path relative to project root (JPEG, PNG, GIF, WEBP, BMP). First tool in the ecosystem to perform pixel-level image analysis. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'path' => 
        array (
          'type' => 'string',
          'description' => 'Path to the image file relative to project root (e.g. \'storage/agent/workspace/downloads/image.png\').',
        ),
        'max_colors' => 
        array (
          'type' => 'integer',
          'description' => 'Maximum dominant colors to return (1-20, default: 8).',
        ),
        'histogram_buckets' => 
        array (
          'type' => 'integer',
          'description' => 'Number of buckets for the brightness histogram (2-32, default: 10).',
        ),
